@@ -0,0 +1,125 @@
+/**
+ * Preferences service — business logic for managing user notification preferences.
+ *
+ * Depends on:
+ * - PreferencesRepository (data layer) for persistence
+ *
+ * Provides methods to get, create, and update user preferences. When no
+ * preferences exist for a user, returns sensible defaults (all notifications
+ * enabled at immediate frequency).
+ *
+ * Used by NotificationService to check whether a notification should be
+ * delivered to a given user.
+ */
+
+import type { UserPreferences, UpdateEmailPreferencesInput } from '../models/user-preferences.js';
+import { DEFAULT_EMAIL_PREFERENCES } from '../models/user-preferences.js';
+import type { NotificationType } from '../models/notification.js';
+import type { PreferencesRepository } from '../repositories/preferences.repository.js';
+import { Logger } from '../utils/logger.js';
+
+let nextId = 1;
+
+function generateId(): string {
+  return `pref-${String(nextId++).padStart(4, '0')}`;
+}
+
+export function resetPreferencesIdCounter(): void {
+  nextId = 1;
+}
+
+export class PreferencesService {
+  private logger = new Logger('PreferencesService');
+
+  constructor(private preferencesRepository: PreferencesRepository) {}
+
+  /**
+   * Get preferences for a user. Returns stored preferences if they exist,
+   * otherwise returns defaults without persisting them.
+   */
+  getPreferences(userId: string): UserPreferences {
+    const existing = this.preferencesRepository.findByUserId(userId);
+    if (existing) {
+      return existing;
+    }
+
+    this.logger.info(`No preferences found for user ${userId}, returning defaults`);
+    const now = new Date();
+    return {
+      id: '',
+      userId,
+      email: { ...DEFAULT_EMAIL_PREFERENCES, subscribedCategories: [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories] },
+      createdAt: now,
+      updatedAt: now,
+    };
+  }
+
+  /**
+   * Create or update email preferences for a user. If no preferences record
+   * exists, one is created. Otherwise the existing record is updated.
+   */
+  updateEmailPreferences(userId: string, input: UpdateEmailPreferencesInput): UserPreferences {
+    this.logger.info(`Updating email preferences for user ${userId}`);
+
+    const existing = this.preferencesRepository.findByUserId(userId);
+
+    if (existing) {
+      const updatedEmail = {
+        enabled: input.enabled ?? existing.email.enabled,
+        frequency: input.frequency ?? existing.email.frequency,
+        subscribedCategories: input.subscribedCategories ?? [...existing.email.subscribedCategories],
+      };
+
+      return this.preferencesRepository.update(existing.id, {
+        email: updatedEmail,
+        updatedAt: new Date(),
+      });
+    }
+
+    // Create new preferences record
+    const now = new Date();
+    const prefs: UserPreferences = {
+      id: generateId(),
+      userId,
+      email: {
+        enabled: input.enabled ?? DEFAULT_EMAIL_PREFERENCES.enabled,
+        frequency: input.frequency ?? DEFAULT_EMAIL_PREFERENCES.frequency,
+        subscribedCategories: input.subscribedCategories ?? [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories],
+      },
+      createdAt: now,
+      updatedAt: now,
+    };
+
+    this.preferencesRepository.save(prefs);
+    this.logger.info(`Created preferences ${prefs.id} for user ${userId}`);
+    return prefs;
+  }
+
+  /**
+   * Check whether a notification should be sent to a user via email.
+   * Returns true if:
+   * - Email is enabled
+   * - Frequency is not 'never'
+   * - The notification type is in the user's subscribed categories
+   */
+  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
+    const prefs = this.getPreferences(userId);
+
+    if (!prefs.email.enabled) {
+      this.logger.info(`Email disabled for user ${userId}, skipping ${notificationType}`);
+      return false;
+    }
+
+    if (prefs.email.frequency === 'never') {
+      this.logger.info(`Email frequency is 'never' for user ${userId}, skipping ${notificationType}`);
+      return false;
+    }
+
+    if (!prefs.email.subscribedCategories.includes(notificationType)) {
+      this.logger.info(`User ${userId} not subscribed to ${notificationType}, skipping`);
+      return false;
+    }
+
+    return true;
+  }
+}

