/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications. Currently supports
 * email as the only notification channel, with settings for frequency and
 * category subscriptions.
 *
 * Design: Preferences are per-user and default to all notifications enabled
 * at immediate frequency. The PreferencesService provides defaults for users
 * who haven't explicitly set preferences.
 */

import type { NotificationType } from './notification.js';

/**
 * How often email notifications are delivered.
 * - 'immediate': sent as they occur
 * - 'daily_digest': batched into a daily summary
 * - 'weekly_digest': batched into a weekly summary
 * - 'never': email notifications disabled via frequency
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest' | 'never';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  enabled: boolean;
  frequency: EmailFrequency;
  subscribedCategories: NotificationType[];
}

/**
 * Full user preferences record.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for updating email preferences. All fields optional — only
 * provided fields are updated.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * All notification categories a user can subscribe to.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'user_welcome',
  'user_updated',
];

/**
 * Default email preferences for new users.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailPreferences = {
  enabled: true,
  frequency: 'immediate',
  subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
};

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Depends on the Database utility layer for storage.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: JSON.parse(record['email'] as string),
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      email: JSON.stringify(entity.email),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences for a specific user.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — business logic for managing user notification preferences.
 *
 * Depends on:
 * - PreferencesRepository (data layer) for persistence
 *
 * Provides methods to get, create, and update user preferences. When no
 * preferences exist for a user, returns sensible defaults (all notifications
 * enabled at immediate frequency).
 *
 * Used by NotificationService to check whether a notification should be
 * delivered to a given user.
 */

import type { UserPreferences, UpdateEmailPreferencesInput } from '../models/user-preferences.js';
import { DEFAULT_EMAIL_PREFERENCES } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns stored preferences if they exist,
   * otherwise returns defaults without persisting them.
   */
  getPreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    this.logger.info(`No preferences found for user ${userId}, returning defaults`);
    const now = new Date();
    return {
      id: '',
      userId,
      email: { ...DEFAULT_EMAIL_PREFERENCES, subscribedCategories: [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories] },
      createdAt: now,
      updatedAt: now,
    };
  }

  /**
   * Create or update email preferences for a user. If no preferences record
   * exists, one is created. Otherwise the existing record is updated.
   */
  updateEmailPreferences(userId: string, input: UpdateEmailPreferencesInput): UserPreferences {
    this.logger.info(`Updating email preferences for user ${userId}`);

    const existing = this.preferencesRepository.findByUserId(userId);

    if (existing) {
      const updatedEmail = {
        enabled: input.enabled ?? existing.email.enabled,
        frequency: input.frequency ?? existing.email.frequency,
        subscribedCategories: input.subscribedCategories ?? [...existing.email.subscribedCategories],
      };

      return this.preferencesRepository.update(existing.id, {
        email: updatedEmail,
        updatedAt: new Date(),
      });
    }

    // Create new preferences record
    const now = new Date();
    const prefs: UserPreferences = {
      id: generateId(),
      userId,
      email: {
        enabled: input.enabled ?? DEFAULT_EMAIL_PREFERENCES.enabled,
        frequency: input.frequency ?? DEFAULT_EMAIL_PREFERENCES.frequency,
        subscribedCategories: input.subscribedCategories ?? [...DEFAULT_EMAIL_PREFERENCES.subscribedCategories],
      },
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(prefs);
    this.logger.info(`Created preferences ${prefs.id} for user ${userId}`);
    return prefs;
  }

  /**
   * Check whether a notification should be sent to a user via email.
   * Returns true if:
   * - Email is enabled
   * - Frequency is not 'never'
   * - The notification type is in the user's subscribed categories
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.getPreferences(userId);

    if (!prefs.email.enabled) {
      this.logger.info(`Email disabled for user ${userId}, skipping ${notificationType}`);
      return false;
    }

    if (prefs.email.frequency === 'never') {
      this.logger.info(`Email frequency is 'never' for user ${userId}, skipping ${notificationType}`);
      return false;
    }

    if (!prefs.email.subscribedCategories.includes(notificationType)) {
      this.logger.info(`User ${userId} not subscribed to ${notificationType}, skipping`);
      return false;
    }

    return true;
  }
}

